#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        long long pow = 1LL<<N;
        long long cnt = ( (long long)N * pow ) % MOD;
        cout<<cnt<<"\n";
        long long mask = pow-1;
        for(long long i=0;i<pow;i++){
            long long val = (i ^ (i>>1)) ^ mask;
            cout<<val<<(i+1==pow? '\n':' ');
        }
    }
    return 0;
}

